  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare.module_finite_HModule_of_HModule'_X₄_curve}
  \uses{thm:Scheme_AffineCoverMVSquare_module_finite_HModule_of_HModule_prime_X4, def:Scheme_toModuleKSheaf}
